import { useState } from "react";
import { createPost } from "../firebase/posts";
import { generateBlog } from "../ai/aiService";
import toast from "react-hot-toast";

export default function WriteModal({ onClose, onPublished, isDemo, onDemoPublish }) {
  const [form, setForm] = useState({
    title: "",
    content: "",
  });

  const [aiDraft, setAiDraft] = useState("");
  const [loading, setLoading] = useState(false);

  const set = (k, v) => setForm((f) => ({ ...f, [k]: v }));

  // 🔥 AI GENERATE
  const handleGenerate = async () => {
    if (!form.title.trim()) {
      toast.error("Enter title first");
      return;
    }

    setLoading(true);
    toast.loading("Generating...");

    try {
      const content = await generateBlog(form.title);

      setAiDraft(content);

      toast.dismiss();
      toast.success("AI content ready!");
    } catch {
      toast.dismiss();
      toast.error("AI failed");
    }

    setLoading(false);
  };

  // 🔥 USE AI CONTENT
  const useContent = () => {
    setForm((f) => ({ ...f, content: aiDraft }));
  };

  // 🔥 PUBLISH
  const handlePublish = async () => {
    if (!form.title || !form.content) {
      toast.error("Fill all fields");
      return;
    }

    const postData = { ...form };

    if (isDemo) {
      onDemoPublish?.(postData);
    } else {
      await createPost(postData);
    }

    toast.success("Published!");
    onPublished?.();
    onClose();
  };

  return (
    <div style={s.backdrop}>
      <div style={s.modal}>
        <h2>✍️ Write Post</h2>

        <input
          style={s.input}
          placeholder="Enter title..."
          value={form.title}
          onChange={(e) => set("title", e.target.value)}
        />

        <textarea
          style={s.textarea}
          placeholder="Write your content..."
          value={form.content}
          onChange={(e) => set("content", e.target.value)}
        />

        {/* 🔥 AI BUTTON */}
        <button style={s.primaryBtn} onClick={handleGenerate}>
          ✨ Generate Blog with AI
        </button>

        {/* 🔥 AI PREVIEW */}
        {aiDraft && (
          <div style={s.preview}>
            <h4>🤖 AI Draft</h4>
            <div style={s.previewText}>{aiDraft}</div>

            <div style={s.actions}>
              <button style={s.useBtn} onClick={useContent}>
                ✅ Use
              </button>
              <button style={s.secondaryBtn} onClick={handleGenerate}>
                🔄 Regenerate
              </button>
            </div>
          </div>
        )}

        <button style={s.publishBtn} onClick={handlePublish}>
          🚀 Publish
        </button>
      </div>
    </div>
  );
}

const s = {
  backdrop: {
    position: "fixed",
    inset: 0,
    background: "rgba(0,0,0,0.5)",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
  },

  modal: {
    background: "#fff",
    padding: 20,
    borderRadius: 12,
    width: 500,
  },

  input: {
    width: "100%",
    padding: 10,
    marginBottom: 10,
  },

  textarea: {
    width: "100%",
    height: 120,
    padding: 10,
    marginBottom: 10,
  },

  primaryBtn: {
    width: "100%",
    padding: 12,
    background: "#2563eb",
    color: "#fff",
    border: "none",
    borderRadius: 10,
    marginBottom: 10,
  },

  secondaryBtn: {
    flex: 1,
    padding: 10,
  },

  publishBtn: {
    width: "100%",
    padding: 12,
    background: "#1d4ed8",
    color: "#fff",
    border: "none",
    borderRadius: 10,
  },

  preview: {
    border: "1px solid #ddd",
    padding: 10,
    marginBottom: 10,
  },

  previewText: {
    maxHeight: 150,
    overflow: "auto",
    marginBottom: 10,
  },

  actions: {
    display: "flex",
    gap: 10,
  },

  useBtn: {
    flex: 1,
    background: "green",
    color: "#fff",
  },
};
